def main()->int:
 ap=argparse.ArgumentParser();ap.add_argument('--root',type=Path,default=None);ap.add_argument('--expected-predecessor-head',required=True);ap.add_argument('--expected-predecessor-tree',required=True);a=ap.parse_args();root=(a.root if a.root is not None else Path.cwd()).resolve();out=root/OUTREL;checks={};errors={}
 def ck(n:str,v:bool,d:Any=None):checks[n]=bool(v);errors.setdefault(n,d) if not v and d is not None else None
