 if missing:
  result={'schema_version':1,'verification_kind':'e2-r1-ut4-android-data-policy','check_count':len(checks),'pass_count':sum(checks.values()),'checks':checks,'errors':errors,'failed_checks':[k for k,v in checks.items() if not v],'pass':False};print(json.dumps(result,indent=2,sort_keys=True));return 1
 auth=load(out/'android-data-policy-authority.json');gate=load(out/'ut4-gate-diagnostics.json');audit=load(out/'independent-audit.json');scan=load(out/'negative-path-scans.json');ro=load(out/'read-only-installation-behavior.json');upd=load(out/'data-update-evidence.json');venv=load(out/'venv-writable-state-policy.json');state=load(root/'docs/current/STATE.json');task=load(root/'docs/current/AGENT_TASK.json');catalog=load(root/'docs/agent/TASK_CATALOG.json');registry=load(root/'docs/documentation/document-registry.json')
