 ck('state_revision',state.get('state_revision')==11);ck('state_predecessor',state.get('predecessor')=={'commit':a.expected_predecessor_head,'tree':a.expected_predecessor_tree});ck('state_next',state.get('next_action_class')=='execute-e2-r1-ut5-feature-capability-and-product-surface-qualification');ck('state_gate',state.get('program',{}).get('gate',{}).get('id')=='E2-R1/UT-5');authority_sha=sha(out/'android-data-policy-authority.json');binding=[x for x in state.get('accepted_authorities',[]) if x.get('path')==f'{OUTREL}/android-data-policy-authority.json'];ck('state_binding',len(binding)==1 and binding[0].get('sha256')==authority_sha)
 ck('current_task',task.get('task',{}).get('id')=='E2-R1-UT-5' and task.get('state_revision')==11);ut5=next((t for t in catalog.get('tasks',[]) if t.get('task_id')=='E2-R1-UT-5'),{});ut6=next((t for t in catalog.get('tasks',[]) if t.get('task_id')=='E2-R1-UT-6'),{});ck('ut5_activation',ut5.get('activation',{}).get('status')=='ready' and ut5.get('activation',{}).get('accepted_authority_sha256')==authority_sha);ck('ut5_completion_contract',ut5.get('completion_contract',{}).get('pass',{}).get('successor_task_id')=='E2-R1-UT-6');ck('ut6_cataloged',ut6.get('activation',{}).get('status')=='blocked-on-predecessor-authority')
 paths={d.get('path') for d in registry.get('documents',[])};need={f'{OUTREL}/{n}' for n in ['README.md','runtime-reproduction.json','ca-trust-candidates.json','timezone-candidates.json','temporary-directory-policy.json','cache-bytecode-and-user-site-policy.json','venv-writable-state-policy.json','read-only-installation-behavior.json','data-update-evidence.json','negative-path-scans.json','ut4-gate-diagnostics.json','independent-audit.json','android-data-policy-authority.json','evidence-freeze.md']};ck('registry_coverage',need<=paths,sorted(need-paths));ck('no_binary_committed',not any(p.suffix in {'.whl','.so','.a','.tar','.zst','.gz'} for p in out.rglob('*') if p.is_file()));ck('generated_views',task.get('generated_from',{}).get('state')=='docs/current/STATE.json')
